import"./hoisted.Cft9kqsr.js";document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".product-card-add-btn").forEach(o=>{o.addEventListener("click",d=>{const e=d.currentTarget,t=JSON.parse(e.dataset.product||"{}");if(window.addToCartGlobal){const n=t.id||t.url?.split("/").pop()||t.title?.replace(/\s+/g,"-").toLowerCase()||"product-"+Math.random().toString(36).substr(2,9);window.addToCartGlobal({...t,id:n,quantity:1})}else console.error("CartDRAWER not ready"),typeof window.openCart=="function"&&window.openCart()})})});
